<template>
  <div class="w-1/2 h-full mx-auto items-center">
    <div class="flex flex-col shadow-xl mt-48">
      <div
        class="
          py-6
          px-14
          bg-gradient-to-tr
          from-red-500
          to-red-200
          rounded-tl-2xl rounded-tr-2xl
          text-center
          space-y-8
        "
      >
        <h2 class="text-white text-xs uppercase">don't miss out the latest</h2>
        <h4 class="text-white text-center font-bold text-xl">
          暂未开放<br />
          还在🚧，暂不对外开放
        </h4>
      </div>
      <div class="flex flex-col py-6 px-8 space-y-5 bg-white">
        <input
          type="password"
          placeholder="请输入密码"
          v-model="password"
          class="
            px-2
            py-2
            border-2
            rounded-md
            border-gray-200
            focus:outline-none
            focus:ring-1 focus:ring-pink-300
            focus:border-transparent
          "
        />
        <button
          @click.stop="submit"
          class="
            w-full
            py-3
            bg-red-400
            text-white
            rounded-md
            text-sm
            focus:outline-none
            focus:ring-2 focus:ring-pink-500
            focus:border-transparent
