</template>
<script>
export default {
  name: "Secret",
  data() {
    return {
      ref: null,
      password: "",
      redirect: null,
    };
  },
  watch: {
    $route: {
      handler: function (route) {
        this.redirect = route.query && route.query.redirect;
      },
      immediate: true,
    },
  },
  methods: {
    submit() {
      try {
        this.$store.dispatch("setSIG", this.password);
        this.$router.push(this.redirect);
      } catch (err) {
        alert("密码错误");
      }
    },
  },
};
</script>
